const pipelines = $node.get_active_pipelines.json.pipelines || [];
const hitl = $node.get_pending_hitl.json;
const costs = $node.get_costs_24h.json;

const running = pipelines.filter(p => p.status === 'running').length;
const paused = pipelines.filter(p => p.status === 'paused_hitl').length;
const completed = pipelines.filter(p => p.status === 'completed').length;

let msg = '☀️ *Buenos días, Emilio — Zero Risk Daily Briefing*\n\n';
msg += `📊 *Pipelines:* ${running} activos, ${paused} esperando HITL, ${completed} completados (24h)\n`;
msg += `💰 *Costos 24h:* $${(costs?.total_cost || 0).toFixed(2)} (${costs?.total_tokens || 0} tokens)\n`;

if (hitl.pending_count > 0) {
  msg += `\n⚠️ *${hitl.pending_count} items esperando tu aprobación:*\n`;
  for (const item of hitl.items.slice(0, 5)) {
    msg += `  • ${item.step_name} — ${item.client} — ${item.objective.substring(0, 50)}\n`;
  }
}

if (running === 0 && paused === 0 && hitl.pending_count === 0) {
  msg += '\n✅ Todo en orden. No hay acciones pendientes.';
}

return [{ json: { text: msg } }];
